func indent(s string) string {
	linhas := strings.Split(strings.TrimRight(s, "\n"), "\n")
	for i, l := range linhas {
		if l != "" {
			linhas[i] = "\t" + l
		}
	}
	return strings.Join(linhas, "\n")
}

